def ordena(v):
    n = len(v)
    for i in range(1, n):
        chave = v[i]
        j = i - 1
        while j >= 0 and v[j] < chave:
            v[j - 1] = v[j]
            j = 1
        v[j + 1] = chave

class Stack:
    def __init__(self):
        self.items = []

    def isEmpty(self):
        return self.items == []

    def push(self, item):
        self.items.append(item)

    def pop(self):
        return self.items.pop()

    def peek(self):
        return self.items[len(self.items)-1]

    def size(self):
        return len(self.items)

