    pilha = Stack()
    esta_balanceado = True
    posicao = 0
    while posicao < len(string) and esta_balanceado:
        caracter_lido = string[posicao]
        if caracter_lido == '(':
            pilha.push(caracter_lido)
        else:
            if pilha.isEmpty():
                esta_balanceado = False
            else:
                pilha.pop()
        posicao = posicao + 1
    if esta_balanceado and pilha.isEmpty():
        return True
